<template><div class="chat-page"><TopBar :title="conversation.buyerName||'买家咨询'" :tag="conversation.orderStatus" back fallback="/messages"><button @click="action('操作')"><CheckSquare/></button><button @click="action('买家资料')"><CircleUserRound/></button></TopBar><main class="message-stream"><p v-if="error" class="error">{{error}}</p><div v-for="(m,i) in messages" :key="m.id"><time v-if="i===0||messages[i-1].createdAt!==m.createdAt">{{formatBeijingDateTime(m.createdAt)}}</time><MessageBubble :item="m"/></div></main><QuickActionPanel v-if="more" @action="action"/><ChatComposer @send="send" @more="more=!more" @action="action"/><div v-if="tip" class="toast" @click="tip=''">{{tip}}功能暂为占位</div></div></template><script setup lang="ts">import{onMounted,ref,nextTick}from'vue';import{CheckSquare,CircleUserRound}from'lucide-vue-next';import{route}from'../router';import{formatBeijingDateTime}from'../utils/time';import TopBar from'../components/TopBar.vue';import MessageBubble from'../components/MessageBubble.vue';import ChatComposer from'../components/ChatComposer.vue';import QuickActionPanel from'../components/QuickActionPanel.vue';const id=route.value.chatId,conversation=ref<any>({}),messages=ref<any[]>([]),error=ref(''),more=ref(false),tip=ref('');const action=(x:any)=>tip.value=Array.isArray(x)?x[0]:x;async function load(){try{const[c,m]=await Promise.all([fetch(`/api/koshop-seller/messages/conversations/${id}`).then(r=>r.json()),fetch(`/api/koshop-seller/messages/conversations/${id}/messages`).then(r=>r.json())]);conversation.value=c.conversation||{};messages.value=m.items||[];fetch(`/api/koshop-seller/messages/conversations/${id}/read`,{method:'POST'});nextTick(()=>scrollTo(0,document.body.scrollHeight))}catch{error.value='消息加载失败'}}async function send(content:string){error.value='';try{const j=await(await fetch(`/api/koshop-seller/messages/conversations/${id}/messages`,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({content})})).json();if(!j.ok)throw Error(j.message);messages.value.push(j.message)}catch(e:any){error.value=e.message||'发送失败，请稍后重试'}}onMounted(load)</script>
